// 转维流程相关 Mock 数据 — 完整数据模型

// ========== 枚举类型 ==========

export type PipelineNodeStatus = 'not_started' | 'in_progress' | 'success' | 'failed'
export type RoleNodeStatus = 'not_started' | 'in_progress' | 'completed' | 'rejected'
export type EntryStatus = 'not_entered' | 'draft' | 'entered'
export type AICheckStatus = 'not_started' | 'in_progress' | 'passed' | 'failed'
export type ReviewStatus = 'not_reviewed' | 'reviewing' | 'passed' | 'rejected'
export type PipelineStatus = 'in_progress' | 'completed' | 'cancelled'
export type RoleType = 'SPM' | 'TPM' | 'SQA' | '底软' | '系统' | '影像'
export type PipelineRole = 'SPM' | '测试' | '底软' | '系统' | '影像'

// ========== 核心接口 ==========

export interface TMTeamMember {
  id: string
  name: string
  role: RoleType
  department: string
  avatar?: string
}

export interface ProjectTeam {
  research: TMTeamMember[]
  maintenance: TMTeamMember[]
}

export interface RoleProgress {
  role: PipelineRole
  entryStatus: RoleNodeStatus
  reviewStatus: RoleNodeStatus
}

export interface PipelineState {
  projectInit: PipelineNodeStatus
  dataEntry: PipelineNodeStatus
  maintenanceReview: PipelineNodeStatus
  sqaReview: PipelineNodeStatus
  infoChange: PipelineNodeStatus
  roleProgress: RoleProgress[]
}

export interface TransferApplication {
  id: string
  projectId: string
  projectName: string
  applicant: string
  applicantId: string
  team: ProjectTeam
  plannedReviewDate: string
  remark: string
  status: PipelineStatus
  cancelReason?: string
  pipeline: PipelineState
  createdAt: string
  updatedAt: string
}

export interface Deliverable {
  id: string
  name: string
  url: string
  type: 'file' | 'link'
}

export interface CheckListItem {
  id: string
  applicationId: string
  seq: number
  type: string
  checkItem: string
  responsibleRole: PipelineRole
  entryPerson: string
  entryPersonId: string
  reviewPerson: string
  reviewPersonId: string
  aiCheckRule: string
  deliverables: Deliverable[]
  entryContent?: string
  entryStatus: EntryStatus
  aiCheckStatus: AICheckStatus
  aiCheckResult?: string
  reviewStatus: ReviewStatus
  reviewComment?: string
  delegatedTo?: string
}

export interface ReviewElement {
  id: string
  applicationId: string
  seq: number
  standard: string
  description: string
  remark: string
  responsibleRole: PipelineRole
  entryPerson: string
  entryPersonId: string
  reviewPerson: string
  reviewPersonId: string
  aiCheckRule: string
  deliverables: Deliverable[]
  entryContent?: string
  entryStatus: EntryStatus
  aiCheckStatus: AICheckStatus
  aiCheckResult?: string
  reviewStatus: ReviewStatus
  reviewComment?: string
  delegatedTo?: string
}

export interface BlockTask {
  id: string
  applicationId: string
  description: string
  resolution: string
  responsiblePerson: string
  department: string
  deadline: string
  status: 'open' | 'resolved' | 'cancelled'
  createdAt: string
}

export interface LegacyTask {
  id: string
  applicationId: string
  description: string
  responsiblePerson: string
  department: string
  deadline: string
  status: 'open' | 'resolved' | 'cancelled'
  createdAt: string
}

export interface HistoryRecord {
  id: string
  applicationId: string
  action: string
  operator: string
  detail: string
  timestamp: string
}

export interface CloseReviewRow {
  role: string
  responsiblePerson: string
  conclusion: 'N/A' | 'PASS' | 'Fail'
  comment: string
}

// ========== 配置中心模板接口（保留） ==========

export interface CheckListTemplate {
  id: number
  type: string
  checkItem: string
  responsibleRole: string
  entryRole: string
  reviewRole: string
  aiCheckRule: string
}

export interface ReviewElementTemplate {
  id: number
  standard: string
  description: string
  remark: string
  responsibleRole: string
  entryRole: string
  reviewRole: string
  aiCheckRule: string
}

// 版本管理接口
export interface TemplateVersion {
  version: string
  date: string
  itemCount: number
  isCurrent: boolean
}

export interface VersionDiffItem {
  checkItem?: string
  description?: string
  status: '新增' | '修改' | '删除'
}

// 兼容旧代码 — TeamMember alias
export type TeamMember = TMTeamMember

